  }
  const auto *ModInst = StackMgr.getModule();
  assuming(ModInst);
  Span<const AST::SubType *const> GotTypeList = ModInst->getTypeList();
  if (!VT.isAbsHeapType() && !Ref.isNull()) {
    auto *Inst = Ref.getPtr<Runtime::Instance::CompositeBase>();
    if (Inst->getModule()) {
